     1→'use client';
     2→
     3→import { useLanguage } from './LanguageProvider';
     4→import { Language } from '@/i18n/translations';
     5→import { siteConfig } from '../../site.config';
     6→
     7→const LOCALE_LABELS: Record<string, string> = {
     8→  en: 'EN',
     9→  zh: '中文',
    10→};
    11→
    12→// Short labels for the compact navbar pill
    13→const LOCALE_LABELS_SHORT: Record<string, string> = {
    14→  en: 'EN',
    15→  zh: '中',
    16→};
    17→
    18→interface LanguageSwitchProps {
    19→  /** pill — compact segmented pill for the navbar (default)
    20→   *  text — lightweight typographic links for the footer */
    21→  variant?: 'pill' | 'text';
    22→}
    23→
    24→export default function LanguageSwitch({ variant = 'pill' }: LanguageSwitchProps) {
    25→  const { language, setLanguage, isHydrated } = useLanguage();
    26→  const locales = siteConfig.i18n.locales;
    27→
    28→  if (locales.length < 2) return null;
    29→
    30→  // SSR placeholder — reserve space to avoid layout shift
    31→  if (!isHydrated) {
    32→    return <div className={variant === 'pill' ? 'w-[52px] h-8' : 'w-16 h-4'} aria-hidden="true" />;
    33→  }
    34→
    35→  const currentIndex = locales.indexOf(language);
    36→  const nextLocale = locales[(currentIndex + 1) % locales.length] as Language;
    37→
    38→  // ── Text variant: quiet typographic links for the footer ──────────────────
    39→  if (variant === 'text') {
    40→    if (locales.length === 2) {
    41→      const [a, b] = locales as Language[];
    42→      return (
    43→        <span className="flex items-center gap-1.5" role="group" aria-label="Language">
    44→          <button
    45→            type="button"
    46→            onClick={() => setLanguage(a)}
    47→            aria-pressed={language === a}
    48→            className={`text-xs font-sans tracking-wide transition-colors duration-150 ${
    49→              language === a
    50→                ? 'text-foreground/80 font-medium cursor-default'
    51→                : 'text-muted/50 hover:text-foreground/70 cursor-pointer'
    52→            }`}
    53→          >
    54→            {LOCALE_LABELS[a] ?? a.toUpperCase()}
    55→          </button>
    56→          <span className="text-muted/25 select-none" aria-hidden="true">·</span>
    57→          <button
    58→            type="button"
    59→            onClick={() => setLanguage(b)}
    60→            aria-pressed={language === b}
    61→            className={`text-xs font-sans tracking-wide transition-colors duration-150 ${
    62→              language === b
    63→                ? 'text-foreground/80 font-medium cursor-default'
    64→                : 'text-muted/50 hover:text-foreground/70 cursor-pointer'
    65→            }`}
    66→          >
    67→            {LOCALE_LABELS[b] ?? b.toUpperCase()}
    68→          </button>
    69→        </span>
    70→      );
    71→    }
    72→    // 3+ locales text fallback: cycle on click
    73→    return (
    74→      <button
    75→        type="button"
    76→        onClick={() => setLanguage(nextLocale)}
    77→        className="text-xs font-sans text-muted/60 hover:text-foreground/80 transition-colors duration-150"
    78→        aria-label={`Switch to ${LOCALE_LABELS[nextLocale] ?? nextLocale}`}
    79→      >
    80→        {LOCALE_LABELS[language] ?? language.toUpperCase()}
    81→      </button>
    82→    );
    83→  }
    84→
    85→  // ── Pill variant: compact segmented pill for the navbar ───────────────────
    86→  if (locales.length === 2) {
    87→    const [a, b] = locales as Language[];
    88→    return (
    89→      <button
    90→        onClick={() => setLanguage(nextLocale)}
    91→        className="group flex items-center rounded-full border border-muted/20 bg-transparent hover:border-accent/40 transition-all duration-200"
    92→        aria-label={`Switch language to ${LOCALE_LABELS[nextLocale] ?? nextLocale}`}
    93→        title={`Switch to ${LOCALE_LABELS[nextLocale] ?? nextLocale}`}
    94→      >
    95→        <span
    96→          className={`px-2 py-1 rounded-full text-[11px] font-sans font-bold tracking-wider transition-all duration-200 ${
    97→            language === a
    98→              ? 'text-accent bg-accent/10'
    99→              : 'text-muted/50 group-hover:text-foreground/60'
   100→          }`}
   101→        >
   102→          {LOCALE_LABELS_SHORT[a] ?? a.toUpperCase()}
   103→        </span>
   104→        <span className="text-muted/25 text-[10px] select-none -mx-0.5" aria-hidden="true">·</span>
   105→        <span
   106→          className={`px-2 py-1 rounded-full text-[11px] font-sans font-bold tracking-wider transition-all duration-200 ${
   107→            language === b
   108→              ? 'text-accent bg-accent/10'
   109→              : 'text-muted/50 group-hover:text-foreground/60'
   110→          }`}
   111→        >
   112→          {LOCALE_LABELS_SHORT[b] ?? b.toUpperCase()}
   113→        </span>
   114→      </button>
   115→    );
   116→  }
   117→
   118→  // 3+ locales pill fallback: show current, click cycles
   119→  return (
   120→    <button
   121→      onClick={() => setLanguage(nextLocale)}
   122→      className="w-8 h-8 flex items-center justify-center text-foreground/80 hover:text-accent transition-colors duration-200 text-[11px] font-sans font-bold tracking-wider"
   123→      aria-label={`Language: ${LOCALE_LABELS_SHORT[language] ?? language}. Click to switch to ${LOCALE_LABELS_SHORT[nextLocale] ?? nextLocale}`}
   124→    >
   125→      {LOCALE_LABELS_SHORT[language] ?? language.toUpperCase()}
   126→    </button>
   127→  );
   128→}
   129→

