     1→'use client';
     2→
     3→import React, { createContext, useContext, useState, useEffect, useMemo } from 'react';
     4→import { siteConfig } from '../../site.config';
     5→import { translations, Language, TranslationKey } from '../i18n/translations';
     6→import { buildFeatureOverrides } from '@/lib/i18n';
     7→
     8→interface LanguageContextType {
     9→  language: Language;
    10→  isHydrated: boolean;
    11→  setLanguage: (lang: Language) => void;
    12→  t: (key: TranslationKey) => string;
    13→  tWith: (key: TranslationKey, params: Record<string, string | number>) => string;
    14→}
    15→
    16→const LanguageContext = createContext<LanguageContextType | undefined>(undefined);
    17→
    18→export function LanguageProvider({ children }: { children: React.ReactNode }) {
    19→  // Always initialize with site default to match server-side rendering
    20→  const [language, setLanguageState] = useState<Language>(siteConfig.i18n.defaultLocale as Language);
    21→  const [isHydrated, setIsHydrated] = useState(false);
    22→
    23→  useEffect(() => {
    24→    // Only access localStorage and browser language after component is mounted (client-side)
    25→    const savedLang = localStorage.getItem('amytis-language') as Language;
    26→    
    27→    // Use requestAnimationFrame to avoid cascading render lint error
    28→    const rafId = requestAnimationFrame(() => {
    29→      if (savedLang && translations[savedLang]) {
    30→        setLanguageState(savedLang);
    31→      }
    32→      setIsHydrated(true);
    33→    });
    34→    return () => cancelAnimationFrame(rafId);
    35→  }, []);
    36→
    37→  const setLanguage = (lang: Language) => {
    38→    setLanguageState(lang);
    39→    localStorage.setItem('amytis-language', lang);
    40→  };
    41→
    42→  const activeLang = (isHydrated ? language : siteConfig.i18n.defaultLocale) as Language;
    43→
    44→  // Recompute only when the active language changes; siteConfig is static
    45→  const featureOverrides = useMemo(
    46→    () => buildFeatureOverrides(activeLang),
    47→    [activeLang],
    48→  );
    49→
    50→  /**
    51→   * Translates a key.
    52→   * Returns the default locale translation if not hydrated to prevent hydration mismatch.
    53→   * Feature name overrides from siteConfig.features.*.name take precedence.
    54→   */
    55→  const t = (key: TranslationKey) => {
    56→    if (key in featureOverrides) return featureOverrides[key]!;
    57→    return translations[activeLang][key] || key;
    58→  };
    59→
    60→  /**
    61→   * Translates a key with parameters.
    62→   */
    63→  const tWith = (key: TranslationKey, params: Record<string, string | number>) => {
    64→    let result = (key in featureOverrides ? featureOverrides[key]! : translations[activeLang][key]) || key;
    65→    for (const [name, value] of Object.entries(params)) {
    66→      result = result.replace(new RegExp(`\\{${name}\\}`, 'g'), String(value));
    67→    }
    68→    return result;
    69→  };
    70→
    71→  return (
    72→    <LanguageContext.Provider value={{ language, isHydrated, setLanguage, t, tWith }}>
    73→      {children}
    74→    </LanguageContext.Provider>
    75→  );
    76→}
    77→
    78→export function useLanguage() {
    79→  const context = useContext(LanguageContext);
    80→  if (context === undefined) {
    81→    throw new Error('useLanguage must be used within a LanguageProvider');
    82→  }
    83→  return context;
    84→}
    85→

