     1→import { translations, Language, TranslationKey } from '@/i18n/translations';
     2→import { siteConfig } from '../../site.config';
     3→
     4→// ── Feature name overrides ────────────────────────────────────────────────
     5→//
     6→// When a user configures e.g. features.series.name.zh = "专栏", these maps
     7→// tell us which translation keys should reflect that name.
     8→
     9→/** Translation keys whose value IS the feature name (simple substitution). */
    10→const FEATURE_SIMPLE_KEYS: Record<string, TranslationKey[]> = {
    11→  series: ['series'],
    12→  books:  ['books', 'book'],
    13→  flow:   ['flow'],
    14→  posts:  ['posts'],
    15→};
    16→
    17→/** Translation keys that CONTAIN the feature name as a substring (compound substitution). */
    18→const FEATURE_COMPOUND_KEYS: Record<string, TranslationKey[]> = {
    19→  series: ['curated_series', 'all_series', 'view_full_series'],
    20→  books:  ['all_books', 'selected_books'],
    21→  flow:   ['all_flows', 'recent_notes'],
    22→  posts:  [],
    23→};
    24→
    25→function substituteInTranslation(original: string, from: string, to: string): string | null {
    26→  if (original.includes(from)) return original.replaceAll(from, to);
    27→  // Case-insensitive fallback for languages like English
    28→  if (original.toLowerCase().includes(from.toLowerCase())) {
    29→    const escaped = from.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    30→    return original.replace(new RegExp(escaped, 'gi'), to);
    31→  }
    32→  return null;
    33→}
    34→
    35→/**
    36→ * Build a map of translation overrides derived from siteConfig.features.*.name.
    37→ * Called once per language; results are cached below.
    38→ */
    39→export function buildFeatureOverrides(lang: string): Partial<Record<TranslationKey, string>> {
    40→  const overrides: Partial<Record<TranslationKey, string>> = {};
    41→  const features = siteConfig.features as Record<string, { name?: Record<string, string> } | undefined>;
    42→  const langT = translations[lang as Language] ?? translations.en;
    43→
    44→  for (const [featureKey, featureConfig] of Object.entries(features)) {
    45→    if (!featureConfig?.name) continue;
    46→    const configuredName = featureConfig.name[lang] ?? featureConfig.name['en'];
    47→    if (!configuredName) continue;
    48→
    49→    const simpleKeys = FEATURE_SIMPLE_KEYS[featureKey] ?? [];
    50→    const defaultName = langT[simpleKeys[0]];
    51→    // Skip if no default mapping or name hasn't changed
    52→    if (!defaultName || configuredName === defaultName) continue;
    53→
    54→    for (const key of simpleKeys) {
    55→      overrides[key] = configuredName;
    56→    }
    57→
    58→    for (const key of (FEATURE_COMPOUND_KEYS[featureKey] ?? [])) {
    59→      const original = langT[key];
    60→      if (!original) continue;
    61→      const substituted = substituteInTranslation(original, defaultName, configuredName);
    62→      if (substituted) overrides[key] = substituted;
    63→    }
    64→  }
    65→
    66→  return overrides;
    67→}
    68→
    69→// Module-level cache — siteConfig is static so overrides never change
    70→const _overridesCache: Record<string, Partial<Record<TranslationKey, string>>> = {};
    71→
    72→function getOverrides(lang: string): Partial<Record<TranslationKey, string>> {
    73→  if (!_overridesCache[lang]) _overridesCache[lang] = buildFeatureOverrides(lang);
    74→  return _overridesCache[lang];
    75→}
    76→
    77→/**
    78→ * Server-side translation helper.
    79→ * For client components, use the `useLanguage()` hook instead.
    80→ */
    81→export const t = (key: TranslationKey): string => {
    82→  const lang = siteConfig.i18n.defaultLocale;
    83→  const overrides = getOverrides(lang);
    84→  if (key in overrides) return overrides[key]!;
    85→  return translations[lang as Language]?.[key] || translations.en[key];
    86→};
    87→
    88→export const tWith = (key: TranslationKey, params: Record<string, string | number>): string => {
    89→  let result = t(key);
    90→  for (const [k, v] of Object.entries(params)) {
    91→    result = result.split(`{${k}}`).join(String(v));
    92→  }
    93→  return result;
    94→};
    95→
    96→/**
    97→ * Resolve a locale-aware config value given an explicit language.
    98→ * Shared by both server-side resolveLocale() and client-side components.
    99→ */
   100→export function resolveLocaleValue(value: string | Record<string, string>, lang: string): string {
   101→  if (typeof value === 'string') return value;
   102→  return value[lang] || value.en || Object.values(value)[0] || '';
   103→}
   104→
   105→/**
   106→ * Resolve a config value that may be a plain string or a locale map.
   107→ * Uses the default locale from site config (server-side / build-time).
   108→ * e.g. "Hello" or { en: "Hello", zh: "你好" }
   109→ */
   110→export function resolveLocale(value: string | Record<string, string>): string {
   111→  return resolveLocaleValue(value, siteConfig.i18n.defaultLocale);
   112→}
   113→

