     1→import type { Metadata } from "next";
     2→import localFont from "next/font/local";
     3→import Navbar from "@/components/Navbar";
     4→import Footer from "@/components/Footer";
     5→import Analytics from "@/components/Analytics";
     6→import BrowserDetectionBanner from "@/components/BrowserDetectionBanner";
     7→import { siteConfig } from "../../site.config";
     8→import { ThemeProvider } from "@/components/ThemeProvider";
     9→import { LanguageProvider } from "@/components/LanguageProvider";
    10→import { getAllSeries, getAllBooks, getSeriesData } from "@/lib/markdown";
    11→import { resolveLocale } from "@/lib/i18n";
    12→import "./globals.css";
    13→
    14→const inter = localFont({
    15→  src: [
    16→    {
    17→      path: "../fonts/Inter-Regular.woff2",
    18→      weight: "400",
    19→      style: "normal",
    20→    },
    21→    {
    22→      path: "../fonts/Inter-Bold.woff2",
    23→      weight: "700",
    24→      style: "normal",
    25→    },
    26→  ],
    27→  variable: "--font-inter",
    28→});
    29→
    30→const baskerville = localFont({
    31→  src: [
    32→    {
    33→      path: "../fonts/LibreBaskerville-Regular.ttf",
    34→      weight: "400",
    35→      style: "normal",
    36→    },
    37→    {
    38→      path: "../fonts/LibreBaskerville-Bold.ttf",
    39→      weight: "700",
    40→      style: "normal",
    41→    },
    42→    {
    43→      path: "../fonts/LibreBaskerville-Italic.ttf",
    44→      weight: "400",
    45→      style: "italic",
    46→    },
    47→  ],
    48→  variable: "--font-baskerville",
    49→});
    50→
    51→const siteTwitterHandle = (() => {
    52→  const url = siteConfig.social?.twitter ?? '';
    53→  const m = url.match(/(?:twitter\.com|x\.com)\/([^/?#]+)/);
    54→  return m ? `@${m[1]}` : undefined;
    55→})();
    56→
    57→// Build icon metadata with explicit MIME type so browsers correctly handle
    58→// all formats. Without this, .ico files served via the metadata API lack
    59→// type="image/x-icon" and may be ignored in favour of app/favicon.ico.
    60→const faviconSrc = siteConfig.logo?.favicon || "/icon.svg";
    61→const ext = faviconSrc.split('.').pop()?.toLowerCase();
    62→const faviconMeta =
    63→  ext === 'ico' ? [{ url: faviconSrc, type: 'image/x-icon', sizes: 'any' }] :
    64→  ext === 'png' ? [{ url: faviconSrc, type: 'image/png' }] :
    65→  ext === 'svg' ? [{ url: faviconSrc, type: 'image/svg+xml' }] :
    66→  faviconSrc;
    67→
    68→export const metadata: Metadata = {
    69→  metadataBase: new URL(siteConfig.baseUrl),
    70→  title: resolveLocale(siteConfig.title),
    71→  description: resolveLocale(siteConfig.description),
    72→  icons: {
    73→    icon: faviconMeta,
    74→  },
    75→  openGraph: {
    76→    siteName: resolveLocale(siteConfig.title),
    77→    locale: siteConfig.i18n.defaultLocale,
    78→    type: 'website',
    79→    images: [{ url: siteConfig.ogImage, width: 1200, height: 630 }],
    80→  },
    81→  twitter: {
    82→    card: 'summary',
    83→    site: siteTwitterHandle,
    84→    creator: siteTwitterHandle,
    85→  },
    86→};
    87→
    88→export default function RootLayout({
    89→  children,
    90→}: Readonly<{
    91→  children: React.ReactNode;
    92→}>) {
    93→  const features = siteConfig.features;
    94→
    95→  // Build series list for navbar (only when series feature is enabled)
    96→  const seriesNavItem = siteConfig.nav.find(item => item.url === '/series');
    97→  const featuredSeries = seriesNavItem?.dropdown;
    98→  let seriesList: { name: string; slug: string }[] = [];
    99→  if (features?.series?.enabled !== false) {
   100→    const allSeries = getAllSeries();
   101→    const seriesKeys = Object.keys(allSeries).sort();
   102→    const filteredKeys = featuredSeries && featuredSeries.length > 0
   103→      ? seriesKeys.filter(slug => featuredSeries.includes(slug))
   104→      : [];
   105→    seriesList = filteredKeys.map(slug => ({
   106→      name: getSeriesData(slug)?.title || allSeries[slug][0]?.series || slug,
   107→      slug,
   108→    }));
   109→  }
   110→
   111→  // Build books list for navbar (only when books feature is enabled)
   112→  const booksNavItem = siteConfig.nav.find(item => item.url === '/books');
   113→  const featuredBookSlugs = booksNavItem?.dropdown;
   114→  let booksList: { name: string; slug: string }[] = [];
   115→  if (features?.books?.enabled !== false) {
   116→    const allBooks = getAllBooks();
   117→    booksList = featuredBookSlugs && featuredBookSlugs.length > 0
   118→      ? allBooks
   119→          .filter(book => featuredBookSlugs.includes(book.slug))
   120→          .map(book => ({ name: book.title, slug: book.slug }))
   121→      : [];
   122→  }
   123→
   124→  return (
   125→    <html lang={siteConfig.i18n.defaultLocale} suppressHydrationWarning>
   126→      <body
   127→        className={`${inter.variable} ${baskerville.variable} font-sans min-h-screen transition-colors duration-300`}
   128→        data-palette={siteConfig.themeColor}
   129→        suppressHydrationWarning
   130→      >
   131→        {/* Skip to main content link for accessibility */}
   132→        <a
   133→          href="#main-content"
   134→          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent focus:text-white focus:rounded-lg focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2"
   135→        >
   136→          Skip to main content
   137→        </a>
   138→        <ThemeProvider>
   139→          <LanguageProvider>
   140→            <div className="selection:bg-accent/20 selection:text-accent dark:selection:bg-accent/30 dark:selection:text-accent min-h-screen flex flex-col">
   141→              <Navbar seriesList={seriesList} booksList={booksList} />
   142→              <main id="main-content" className="pt-16 flex-grow">
   143→                <BrowserDetectionBanner updateUrl={siteConfig.browserCheck?.updateUrl} />
   144→                {children}
   145→              </main>
   146→              <Footer />
   147→            </div>
   148→            <Analytics />
   149→          </LanguageProvider>
   150→        </ThemeProvider>
   151→      </body>
   152→    </html>
   153→  );
   154→}

