     9→
    10→export default function Footer() {
    11→  const { t, language } = useLanguage();
    12→  
    13→  return (
    14→    <footer className="bg-muted/5 border-t border-muted/10 mt-auto">
    15→      <div className="max-w-6xl mx-auto px-6 py-16">
    16→        <div className="grid grid-cols-1 lg:grid-cols-4 gap-12 mb-12">
    17→          {/* Brand */}
    18→          <div className="lg:col-span-2">
    19→            <Link href="/" className="flex items-center gap-2 mb-4 group no-underline">
    20→              <svg
    21→                viewBox="0 0 32 32"
    22→                className="w-6 h-6 text-accent group-hover:rotate-12 transition-transform duration-300"
    23→                fill="none"
    24→                stroke="currentColor"
    25→                strokeWidth="2"
    26→                strokeLinecap="round"
    27→                strokeLinejoin="round"
    28→                aria-hidden="true"
    29→              >
